        foreach ($criteria as $keyCriteria => $arr):
            $dataMaster = collect($arr)->except(['subs'])->toArray();
            $dataMaster['title'] = number2roman($keyCriteria+1)." ".$dataMaster['title'];
            $masterCriteria = AuditMasterCriteria::firstOrCreate($dataMaster);
            if (isset($arr['subs'])):
                foreach ($arr['subs'] as $keySub => $sub):
                    $dataSub = collect($sub)->except(['subs','tooltips'])->toArray();
                    $dataSub['title'] = number2roman($keyCriteria+1).".".($keySub+1)." ".$dataSub['title'];
                    $subCriteria = $masterCriteria->sub_criteria()->firstOrCreate($dataSub);
                    
                    if ($subCriteria->has_point){
                        if ($subCriteria->max_point>0){
                            $max = $subCriteria->max_point+1;
                            for ($i=0;$i<$max;$i++){
                                if(array_key_exists("tooltips",$sub)){
                                    $subCriteria->list_points()->create([
                                        'point' => $i,
                                        'tooltip' => $sub["tooltips"][$i],
                                    ]);
                                }else{
                                    $subCriteria->list_points()->create([
                                        'point' => $i]);
                                }
                            }
                        }

                        if ($subCriteria->target_point == null){
                            $subCriteria->list_points()->create([
                            ]);
                        }
                    }
                    if (isset($sub['subs'])):
                        foreach ($sub['subs'] as $keyChild => $child):
                            
                            $child['audit_master_criteria_id'] = $masterCriteria->id;
                            $child['title'] = number2roman($keyCriteria+1).".".($keySub+1).".".($keyChild+1)." ".$child['title'];
                            $dataChild = collect($child)->except(['subs','tooltips'])->toArray();
                            $attribute = $subCriteria->children()->firstOrCreate($dataChild);
                            if ($attribute->has_point){
                                if ($attribute->max_point>0){
                                    $max = $attribute->max_point+1;
                                    for ($i=0;$i<$max;$i++){
                                        if(array_key_exists("tooltips",$child)){
                                            $attribute->list_points()->create([
                                                'point' => $i,
                                                'tooltip' => $child["tooltips"][$i],
                                            ]);
                                        }else {
                                            $attribute->list_points()->create([
                                                'point' => $i,
                                            ]);
                                        }
                                        
                                    }
                                }
                                if ($attribute->target_point == null){
                                    $attribute->list_points()->create([
                                    ]);
                                }
                            }
                        endforeach;
                    endif;
                endforeach;
            endif;
        endforeach;

