        foreach ($criteriaISO14001 as $keyCriteria => $criteria):
            $dataMaster = collect($criteria)->except(['subs','criteria'])->toArray();
            $dataMaster['title'] = ($keyCriteria+4)." ".$dataMaster['title'];
            $masterCriteria = AuditMasterCriteria::firstOrCreate($dataMaster);
            if (isset($criteria['subs'])):
                foreach ($criteria['subs'] as $keySub => $sub):
                    $dataSub = collect($sub)->except(['subs','tooltips','criteria'])->toArray();
                    $dataSub['title'] = ($keyCriteria+4).".".($keySub+1)." ".$dataSub['title'];
                    $subCriteria = $masterCriteria->sub_criteria()->firstOrCreate($dataSub);
                    
                    if ($subCriteria->has_point){
                        if ($subCriteria->max_point>0){
                            $max = $subCriteria->max_point+1;
                            for ($i=0;$i<$max;$i++){
                                if(array_key_exists("tooltips",$sub)){
                                    $subCriteria->list_points()->create([
                                        'point' => $i,
                                        'tooltip' => $sub["tooltips"][$i],
                                    ]);
                                }else{
                                    $subCriteria->list_points()->create([
                                        'point' => $i]);
                                }
                            }
                        }

                        if ($subCriteria->target_point == null){
                            $subCriteria->list_points()->create([
                            ]);
                        }
                    }
                    if (isset($sub['subs'])):
                        foreach ($sub['subs'] as $keyChild => $child):
                            $child['audit_master_criteria_id'] = $masterCriteria->id;
                            $child['title'] = ($keyCriteria+4).".".($keySub+1).".".($keyChild+1)." ".$child['title'];
                            $dataChild = collect($child)->except(['subs','tooltips','criteria'])->toArray();
                            $attribute = $subCriteria->children()->firstOrCreate($dataChild);
                            if ($attribute->has_point){
                                if ($attribute->max_point>0){
                                    $max = $attribute->max_point+1;
                                    for ($i=0;$i<$max;$i++){
                                        if(array_key_exists("tooltips",$child)){
                                            $attribute->list_points()->create([
                                                'point' => $i,
                                                'tooltip' => $child["tooltips"][$i],
                                            ]);
                                        }else {
                                            $attribute->list_points()->create([
                                                'point' => $i,
                                            ]);
                                        }
                                        
                                    }
                                }
                                if ($attribute->target_point == null){
                                    $attribute->list_points()->create([
                                    ]);
                                }
                            }

                            if (isset($child['subs'])):
                                foreach ($child['subs'] as $keySubChild => $subChild):
                                    
                                    $subChild['audit_master_criteria_id'] = $masterCriteria->id;
                                    $subChild['title'] = ($keyCriteria+4).".".($keySub+1).".".($keyChild+1).".".($keySubChild+1)." ".$subChild['title'];
                                    $dataChild = collect($subChild)->except(['subs','tooltips','criteria'])->toArray();
                                    $subAttribute = $attribute->children()->firstOrCreate($dataChild);
                                    if ($subAttribute->has_point){
                                        if ($subAttribute->max_point>0){
                                            $max = $subAttribute->max_point+1;
                                            for ($i=0;$i<$max;$i++){
                                                if(array_key_exists("tooltips",$subChild)){
                                                    $subAttribute->list_points()->create([
                                                        'point' => $i,
                                                        'tooltip' => $subChild["tooltips"][$i],
                                                    ]);
                                                }else {
                                                    $subAttribute->list_points()->create([
                                                        'point' => $i,
                                                    ]);
                                                }
                                                
                                            }
                                        }
                                        if ($subAttribute->target_point == null){
                                            $subAttribute->list_points()->create([
                                            ]);
                                        }
                                    }

                                    if(isset($subChild['criteria'])):
                                        foreach ($subChild['criteria'] as $key => $subChildCriteria) :
                                            $subChildCriteria['audit_master_criteria_id'] = $masterCriteria->id;
                                            $subChildCriteria['title'] = $subChildCriteria['title'];
                                            $dataChild = collect($subChildCriteria)->except(['subs','tooltips','criteria'])->toArray();
                                            $subChildAttribute = $subAttribute->children()->firstOrCreate($dataChild);
                                            if ($subChildAttribute->has_point){
                                                if ($subChildAttribute->max_point>0){
                                                    $max = $subChildAttribute->max_point+1;
                                                    for ($i=0;$i<$max;$i++){
                                                        if(array_key_exists("tooltips",$subChildCriteria)){
                                                            $subChildAttribute->list_points()->create([
                                                                'point' => $i,
                                                                'tooltip' => $subChildCriteria["tooltips"][$i],
                                                            ]);
                                                        }else {
                                                            $subChildAttribute->list_points()->create([
                                                                'point' => $i,
                                                            ]);
                                                        }
                                                        
                                                    }
                                                }
                                                if ($subChildAttribute->target_point == null){
                                                    $subChildAttribute->list_points()->create([
                                                    ]);
                                                }
                                            }
                                        endforeach;
                                    endif;
                                endforeach;
                            endif;

                            if(isset($child['criteria'])):
                                foreach ($child['criteria'] as $key => $subChild) :
                                    $subChild['audit_master_criteria_id'] = $masterCriteria->id;
                                    $subChild['title'] = $subChild['title'];
                                    $dataChild = collect($subChild)->except(['subs','tooltips','criteria'])->toArray();
                                    $subAttribute = $attribute->children()->firstOrCreate($dataChild);
                                    if ($subAttribute->has_point){
                                        if ($subAttribute->max_point>0){
                                            $max = $subAttribute->max_point+1;
                                            for ($i=0;$i<$max;$i++){
                                                if(array_key_exists("tooltips",$subChild)){
                                                    $subAttribute->list_points()->create([
                                                        'point' => $i,
                                                        'tooltip' => $subChild["tooltips"][$i],
                                                    ]);
                                                }else {
                                                    $subAttribute->list_points()->create([
                                                        'point' => $i,
                                                    ]);
                                                }
                                                
                                            }
                                        }
                                        if ($subAttribute->target_point == null){
                                            $subAttribute->list_points()->create([
                                            ]);
                                        }
                                    }
                                endforeach;
                            endif;
                        endforeach;
                    endif;

                    if(isset($sub['criteria'])):
                        foreach ($sub['criteria'] as $key => $child) :
                            $child['audit_master_criteria_id'] = $masterCriteria->id;
                            $child['title'] = $child['title'];
                            $dataChild = collect($child)->except(['subs','tooltips','criteria'])->toArray();
                            $attribute = $subCriteria->children()->firstOrCreate($dataChild);
                            if ($attribute->has_point){
                                if ($attribute->max_point>0){
                                    $max = $attribute->max_point+1;
                                    for ($i=0;$i<$max;$i++){
                                        if(array_key_exists("tooltips",$child)){
                                            $attribute->list_points()->create([
                                                'point' => $i,
                                                'tooltip' => $child["tooltips"][$i],
                                            ]);
                                        }else {
                                            $attribute->list_points()->create([
                                                'point' => $i,
                                            ]);
                                        }
                                        
                                    }
                                }
                                if ($attribute->target_point == null){
                                    $attribute->list_points()->create([
                                    ]);
                                }
                            }
                        endforeach;
                    endif;
                endforeach;
